function UltraChatbotAgentMessageFeedback({
  onVote,
  plan,
}: {
  onVote: (type: "down" | "up") => void | Promise<void>;
  plan: UltraChatbotAgentMessageRenderPlan;
}) {
  return (
    <div className="mt-3 flex items-center gap-2">
      <Button
        aria-label="Helpful"
        disabled={plan.isVotePending}
        onClick={() => onVote("up")}
        size="sm"
        title="Helpful"
        type="button"
        variant={plan.currentVote === true ? "secondary" : "outline"}
      >
        {getHelpfulButtonIcon(plan)}
        {plan.currentVote === true && !plan.isHelpfulPending ? (
          <span>Helpful</span>
        ) : null}
      </Button>
      <Button
        aria-label="Needs work"
        disabled={plan.isVotePending}
        onClick={() => onVote("down")}
        size="sm"
        title="Needs work"
        type="button"
        variant={plan.currentVote === false ? "secondary" : "outline"}
      >
        {getNeedsWorkButtonIcon(plan)}
        {plan.currentVote === false && !plan.isNeedsWorkPending ? (
          <span>Needs work</span>
        ) : null}
      </Button>
    </div>
  );
}

function getHelpfulButtonIcon(
  plan: UltraChatbotAgentMessageRenderPlan
): ReactNode {
  if (plan.isHelpfulPending) {
    return <Spinner className="size-3.5" />;
  }

  return plan.currentVote === true ? (
    <ThumbsUpIcon className="size-3.5 text-emerald-500" />
  ) : (
    <ThumbsUpIcon className="size-3.5" />
  );
}

function getNeedsWorkButtonIcon(
  plan: UltraChatbotAgentMessageRenderPlan
): ReactNode {
  if (plan.isNeedsWorkPending) {
    return <Spinner className="size-3.5" />;
  }

  return plan.currentVote === false ? (
    <ThumbsDownIcon className="size-3.5 text-rose-500" />
  ) : (
    <ThumbsDownIcon className="size-3.5" />
  );
}

function UltraChatbotAgentToolPartView({
  chatId,
  isSandboxUpdating,
  onArtifactOpen,
  onSandboxApprovalResponse,
  part,
}: {
  chatId: string;
  isSandboxUpdating: boolean;
  onArtifactOpen: (documentId: string) => void;
  onSandboxApprovalResponse: UltraChatbotAgentMessagesProps["onSandboxApprovalResponse"];
  part: UltraChatbotAgentToolPart;
}) {
  const documentResult =
    part.state === "output-available" &&
    isUltraChatbotAgentDocumentResult(part.output)
      ? part.output
      : null;
  const weatherResult =
    part.state === "output-available" &&
    isUltraChatbotAgentWeatherResult(part.output)
      ? part.output
      : null;
  const isDocumentTool = isUltraChatbotAgentDocumentTool(part);
  const researchReportResult =
    part.state === "output-available" &&
    part.type === "tool-createResearchReport" &&
    isUltraChatbotAgentResearchReportResult(part.output)
      ? part.output
      : null;
  const knowledgeBaseResult =
    part.state === "output-available" &&
    part.type === "tool-searchKnowledgeBase" &&
    isUltraChatbotAgentKnowledgeBaseResult(part.output)
      ? part.output
      : null;
  const projectDocsResult = getUltraChatbotAgentProjectDocsMcpResult(part);

  if (hasUltraChatbotAgentDocumentToolError(part, isDocumentTool)) {
    return (
      <div className="w-full rounded-xl border border-destructive/30 px-4 py-3 text-destructive text-sm">
        {String(part.output.error)}
      </div>
    );
  }

  if (documentResult && isDocumentTool) {
    return (
      <UltraChatbotAgentDocumentPreview
        chatId={chatId}
        onOpen={onArtifactOpen}
        result={documentResult}
      />
    );
  }

  if (researchReportResult) {
    return <UltraChatbotAgentResearchReport report={researchReportResult} />;
  }

  if (knowledgeBaseResult) {
    return (
      <UltraChatbotAgentKnowledgeBaseResultCard result={knowledgeBaseResult} />
    );
  }

  if (projectDocsResult) {
    return (
      <UltraChatbotAgentProjectDocsResultCard result={projectDocsResult} />
    );
  }

  return (
    <div className="space-y-3">
      {part.type === "tool-enableSandbox" ? (
        <UltraChatbotAgentSandboxConfirmation
          isPending={isSandboxUpdating}
          onApprovalResponse={onSandboxApprovalResponse}
          part={part}
        />
      ) : null}
      <Tool defaultOpen={false}>
        {part.type === "dynamic-tool" ? (
          <ToolHeader
            state={part.state}
            toolName={part.toolName}
            type={part.type}
          />
        ) : (
          <ToolHeader state={part.state} type={part.type} />
        )}
        <ToolContent>
          {part.input ? <ToolInput input={part.input} /> : null}
          {weatherResult ? null : (
            <ToolOutput errorText={part.errorText} output={part.output} />
          )}
          {weatherResult ? (
            <UltraChatbotAgentWeather weather={weatherResult} />
          ) : null}
        </ToolContent>
      </Tool>
    </div>
  );
}

function isUltraChatbotAgentDocumentTool(part: UltraChatbotAgentToolPart) {
  return (
    part.type === "tool-createDocument" ||
    part.type === "tool-editDocument" ||
    part.type === "tool-updateDocument"
  );
}

function hasUltraChatbotAgentDocumentToolError(
  part: UltraChatbotAgentToolPart,
  isDocumentTool: boolean
): part is UltraChatbotAgentToolPart & { output: { error: unknown } } {
  return (
    isDocumentTool &&
    part.state === "output-available" &&
    part.output !== null &&
    part.output !== undefined &&
    typeof part.output === "object" &&
    "error" in part.output
  );
}

function isUltraChatbotAgentWeatherResult(
  output: UltraChatbotAgentToolPart["output"]
): output is Parameters<typeof UltraChatbotAgentWeather>[0]["weather"] {
  if (!output || typeof output !== "object") {
    return false;
  }

  return (
    "current" in output &&
    typeof output.current === "object" &&
    output.current !== null &&
    "daily" in output &&
    typeof output.daily === "object" &&
    output.daily !== null &&
    "current_units" in output &&
    typeof output.current_units === "object" &&
    output.current_units !== null
  );
}

"use client";

import { PaperclipIcon } from "@phosphor-icons/react";
import { Attachments } from "@/components/ai-elements/attachments";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import { Button } from "@/components/ui/button";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import type { ChatStatus, UIMessage } from "ai";
import type { ClipboardEvent, ReactNode } from "react";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { ultraChatbotAgentAcceptedUploadMediaTypes } from "@/lib/ultra-chatbot-agent/attachment-config";
import {
  UltraChatbotAgentPreviewAttachment,
  type UltraChatbotAgentPreviewAttachmentData,
} from "./ultra-chatbot-agent-preview-attachment";

interface PendingUltraChatbotAgentAttachment {
  file: File;
  id: string;
  previewUrl: string;
}

function buildPendingAttachment(
  file: File
): PendingUltraChatbotAgentAttachment {
  return {
    file,
    id: `${file.name}-${file.size}-${file.lastModified}`,
    previewUrl: URL.createObjectURL(file),
  };
}

function revokePendingAttachment(
  attachment: PendingUltraChatbotAgentAttachment
) {
  URL.revokeObjectURL(attachment.previewUrl);
}

function toPreviewData(
  attachment: PendingUltraChatbotAgentAttachment
): UltraChatbotAgentPreviewAttachmentData {
  return {
    filename: attachment.file.name,
    id: attachment.id,
    mediaType: attachment.file.type || "application/octet-stream",
    type: "file",
    url: attachment.previewUrl,
  };
}

async function uploadUltraChatbotAgentAttachment(file: File, chatId: string) {
  const formData = new FormData();
  formData.append("chatId", chatId);
  formData.append("file", file);

  const response = await fetch("/api/demos/ultra-chatbot-agent/files/upload", {
    body: formData,
    credentials: "include",
    method: "POST",
  });

  if (!response.ok) {
    const payload = (await response.json().catch(() => null)) as {
      error?: string;
    } | null;

    throw new Error(payload?.error || "Failed to upload the attachment.");
  }

  const payload = (await response.json()) as {
    contentType: string | null;
    url: string;
  };

  return {
    filename: file.name,
    mediaType: payload.contentType || file.type || "application/octet-stream",
    type: "file" as const,
    url: payload.url,
  };
}

export interface UltraChatbotAgentMultimodalInputProps {
  chatId: string;
  disabled: boolean;
  footerBelow?: ReactNode;
  footerLeading: ReactNode;
  onComposerErrorChange: (message: string | null) => void;
  onSend: (parts: UIMessage["parts"]) => Promise<void>;
  onStop: () => void;
  placeholder: string;
  status: ChatStatus;
}

export function UltraChatbotAgentMultimodalInput({
  chatId,
  disabled,
  footerBelow,
  footerLeading,
  onComposerErrorChange,
  onSend,
  onStop,
  placeholder,
  status,
}: UltraChatbotAgentMultimodalInputProps) {
  const [pendingAttachments, setPendingAttachments] = useState<
    PendingUltraChatbotAgentAttachment[]
  >([]);
  const [uploadingAttachmentIds, setUploadingAttachmentIds] = useState<
    string[]
  >([]);
  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const pendingAttachmentsRef = useRef<PendingUltraChatbotAgentAttachment[]>(
    []
  );
  const isUploading = uploadingAttachmentIds.length > 0;

  useEffect(() => {
    pendingAttachmentsRef.current = pendingAttachments;
  }, [pendingAttachments]);

  useEffect(
    () => () => {
      for (const attachment of pendingAttachmentsRef.current) {
        revokePendingAttachment(attachment);
      }
    },
    []
  );

  const clearFileInput = useCallback(() => {
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  }, []);

  const appendFiles = useCallback(
    (files: File[]) => {
      if (files.length === 0) {
        return;
      }

      onComposerErrorChange(null);
      const nextAttachments = files.map(buildPendingAttachment);

      setPendingAttachments((current) => {
        const replacedIds = new Set(
          nextAttachments.map((attachment) => attachment.id)
        );

        for (const attachment of current) {
          if (replacedIds.has(attachment.id)) {
            revokePendingAttachment(attachment);
          }
        }

        const preserved = current.filter(
          (attachment) => !replacedIds.has(attachment.id)
        );

        return [...preserved, ...nextAttachments];
      });
      clearFileInput();
    },
    [clearFileInput, onComposerErrorChange]
  );

  const removePendingAttachment = useCallback(
    (attachmentId: string) => {
      setPendingAttachments((current) => {
        const attachment = current.find((item) => item.id === attachmentId);

        if (attachment) {
          revokePendingAttachment(attachment);
        }

        return current.filter((item) => item.id !== attachmentId);
      });
      clearFileInput();
    },
    [clearFileInput]
  );

  const previewAttachments = useMemo(
    () => pendingAttachments.map((attachment) => toPreviewData(attachment)),
    [pendingAttachments]
  );

  const handlePaste = useCallback(
    (event: ClipboardEvent<HTMLTextAreaElement>) => {
      const items = event.clipboardData?.items;

      if (!items) {
        return;
      }

      const imageFiles = Array.from(items)
        .filter(
          (item) => item.kind === "file" && item.type.startsWith("image/")
        )
        .map((item) => item.getAsFile())
        .filter((file): file is File => file !== null);

      if (imageFiles.length === 0) {
        return;
      }

      event.preventDefault();
      appendFiles(imageFiles);
    },
    [appendFiles]
  );

  const handleSend = useCallback(
    async (text: string) => {
      const trimmedText = text.trim();

      if (!trimmedText && pendingAttachments.length === 0) {
        return;
      }

      onComposerErrorChange(null);
      setUploadingAttachmentIds(
        pendingAttachments.map((attachment) => attachment.id)
      );

      try {
        const uploadedFileParts = await Promise.all(
          pendingAttachments.map((attachment) =>
            uploadUltraChatbotAgentAttachment(attachment.file, chatId)
          )
        );
        const parts = [
          ...uploadedFileParts,
          ...(trimmedText.length > 0
            ? [{ text: trimmedText, type: "text" as const }]
            : []),
        ];

        await onSend(parts);
        setPendingAttachments((current) => {
          for (const attachment of current) {
            revokePendingAttachment(attachment);
          }

          return [];
        });
        clearFileInput();
      } catch (error) {
        onComposerErrorChange(
          error instanceof Error
            ? error.message
            : "Failed to upload the attachment."
        );
        throw error;
      } finally {
        setUploadingAttachmentIds([]);
      }
    },
    [chatId, clearFileInput, onComposerErrorChange, onSend, pendingAttachments]
  );

  return (
    <div className="space-y-3">
      <input
        accept={ultraChatbotAgentAcceptedUploadMediaTypes.join(",")}
        className="sr-only"
        multiple
        onChange={(event) => appendFiles(Array.from(event.target.files ?? []))}
        ref={fileInputRef}
        type="file"
      />
      <PromptInput onSubmit={({ text }) => handleSend(text)}>
        <PromptInputBody>
          {previewAttachments.length > 0 ? (
            <Attachments className="mb-3" variant="list">
              {previewAttachments.map((attachment) => (
                <UltraChatbotAgentPreviewAttachment
                  attachment={attachment}
                  isUploading={uploadingAttachmentIds.includes(attachment.id)}
                  key={attachment.id}
                  onRemove={() => removePendingAttachment(attachment.id)}
                />
              ))}
            </Attachments>
          ) : null}
          <PromptInputTextarea
            disabled={disabled || isUploading}
            onPaste={handlePaste}
            placeholder={placeholder}
          />
        </PromptInputBody>
        <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
          <div className="flex min-w-0 flex-wrap items-center gap-2">
            {footerLeading}
          </div>
          <div className="flex items-center gap-2">
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  disabled={disabled || isUploading}
                  onClick={() => fileInputRef.current?.click()}
                  size="icon"
                  type="button"
                  variant="outline"
                >
                  <PaperclipIcon className="size-4" />
                </Button>
              </TooltipTrigger>
              <TooltipContent>Add image or PDF</TooltipContent>
            </Tooltip>
            <PromptInputSubmit
              disabled={disabled || isUploading}
              onStop={onStop}
              status={isUploading ? "submitted" : status}
            />
          </div>
        </PromptInputFooter>
      </PromptInput>
      {footerBelow}
    </div>
  );
}

