import { del, list } from "@vercel/blob";

export const ultraChatbotAgentUploadPathRoot = "ultra-chatbot-agent";
export const ultraChatbotAgentUploadListLimit = 1000;

const millisecondsPerDay = 24 * 60 * 60 * 1000;
const ultraChatbotAgentBlobDeleteBatchSize = 100;
const ownedUploadPathSegmentRe = /^[a-zA-Z0-9_-]+$/;

export interface UltraChatbotAgentBlobStorageEnv {
  BLOB_READ_WRITE_TOKEN?: string;
}

export function validateUltraChatbotAgentBlobPathSegment(
  value: string,
  label: string
) {
  const trimmed = value.trim();

  if (!ownedUploadPathSegmentRe.test(trimmed)) {
    throw new Error(
      `${label} must contain only letters, numbers, hyphens, or underscores.`
    );
  }

  return trimmed;
}

export function formatUltraChatbotAgentUploadDateBucket(date: Date) {
  return date.toISOString().slice(0, 10);
}

export function buildUltraChatbotAgentDailyUploadPrefix(input: {
  dateBucket: string;
  visitorId: string;
}) {
  return `${ultraChatbotAgentUploadPathRoot}/${input.visitorId}/${input.dateBucket}/`;
}

export function buildUltraChatbotAgentVisitorUploadPrefix(visitorId: string) {
  return `${ultraChatbotAgentUploadPathRoot}/${visitorId}/`;
}

export function buildUltraChatbotAgentUploadPath(input: {
  chatId: string;
  dateBucket: string;
  filename: string;
  uploadId: string;
  visitorId: string;
}) {
  return `${buildUltraChatbotAgentDailyUploadPrefix({
    dateBucket: input.dateBucket,
    visitorId: input.visitorId,
  })}${input.chatId}/${input.uploadId}-${input.filename}`;
}

async function listUltraChatbotAgentBlobs(input: {
  prefix: string;
  token: string;
}) {
  let cursor: string | undefined;
  const blobs: Awaited<ReturnType<typeof list>>["blobs"] = [];

  do {
    const listOptions: {
      cursor?: string;
      limit: number;
      prefix: string;
      token: string;
    } = {
      limit: ultraChatbotAgentUploadListLimit,
      prefix: input.prefix,
      token: input.token,
    };

    if (cursor) {
      listOptions.cursor = cursor;
    }

    const result = await list(listOptions);
    blobs.push(...result.blobs);
    cursor = result.hasMore ? result.cursor : undefined;
  } while (cursor);

  return blobs;
}

export async function readUltraChatbotAgentBlobUsageForPrefix(input: {
  prefix: string;
  token: string;
}) {
  const blobs = await listUltraChatbotAgentBlobs(input);

  return {
    fileCount: blobs.length,
    totalBytes: blobs.reduce((sum, blob) => sum + blob.size, 0),
  };
}

async function deleteUltraChatbotAgentBlobPathnames(input: {
  pathnames: string[];
  token: string;
}) {
  for (
    let index = 0;
    index < input.pathnames.length;
    index += ultraChatbotAgentBlobDeleteBatchSize
  ) {
    const batch = input.pathnames.slice(
      index,
      index + ultraChatbotAgentBlobDeleteBatchSize
    );

    if (batch.length > 0) {
      await del(batch, { token: input.token });
    }
  }
}

function isUltraChatbotAgentChatBlob(input: {
  chatId: string;
  pathname: string;
  visitorId: string;
}) {
  const [root, visitorId, , chatId] = input.pathname.split("/");
  return (
    root === ultraChatbotAgentUploadPathRoot &&
    visitorId === input.visitorId &&
    chatId === input.chatId
  );
}

export async function deleteUltraChatbotAgentBlobsForChat(input: {
  chatId: string;
  token: string;
  visitorId: string;
}) {
  const visitorId = validateUltraChatbotAgentBlobPathSegment(
    input.visitorId,
    "Visitor id"
  );
  const chatId = validateUltraChatbotAgentBlobPathSegment(
    input.chatId,
    "Chat id"
  );
  const blobs = await listUltraChatbotAgentBlobs({
    prefix: buildUltraChatbotAgentVisitorUploadPrefix(visitorId),
    token: input.token,
  });
  const pathnames = blobs
    .filter((blob) =>
      isUltraChatbotAgentChatBlob({
        chatId,
        pathname: blob.pathname,
        visitorId,
      })
    )
    .map((blob) => blob.pathname);

  await deleteUltraChatbotAgentBlobPathnames({
    pathnames,
    token: input.token,
  });

  return {
    deletedCount: pathnames.length,
  };
}

export async function deleteUltraChatbotAgentBlobsForVisitor(input: {
  token: string;
  visitorId: string;
}) {
  const visitorId = validateUltraChatbotAgentBlobPathSegment(
    input.visitorId,
    "Visitor id"
  );
  const blobs = await listUltraChatbotAgentBlobs({
    prefix: buildUltraChatbotAgentVisitorUploadPrefix(visitorId),
    token: input.token,
  });
  const pathnames = blobs.map((blob) => blob.pathname);

  await deleteUltraChatbotAgentBlobPathnames({
    pathnames,
    token: input.token,
  });

  return {
    deletedCount: pathnames.length,
  };
}

export async function cleanupExpiredUltraChatbotAgentBlobs(input: {
  now?: Date;
  retentionDays: number;
  token: string;
}) {
  const now = input.now ?? new Date();
  const expiresBefore = new Date(
    now.getTime() - input.retentionDays * millisecondsPerDay
  );
  const blobs = await listUltraChatbotAgentBlobs({
    prefix: `${ultraChatbotAgentUploadPathRoot}/`,
    token: input.token,
  });
  const pathnames = blobs
    .filter((blob) => blob.uploadedAt < expiresBefore)
    .map((blob) => blob.pathname);

  await deleteUltraChatbotAgentBlobPathnames({
    pathnames,
    token: input.token,
  });

  return {
    deletedCount: pathnames.length,
    expiresBefore: expiresBefore.toISOString(),
    retentionDays: input.retentionDays,
  };
}

export interface UltraChatbotAgentCapabilities {
  sandboxEnabled: boolean;
}

export function getUltraChatbotAgentDefaultCapabilities(): UltraChatbotAgentCapabilities {
  return {
    sandboxEnabled: false,
  };
}

export function normalizeUltraChatbotAgentCapabilities(
  input: unknown
): UltraChatbotAgentCapabilities {
  const defaults = getUltraChatbotAgentDefaultCapabilities();

  if (!input || typeof input !== "object" || Array.isArray(input)) {
    return defaults;
  }

  return {
    sandboxEnabled:
      "sandboxEnabled" in input && typeof input.sandboxEnabled === "boolean"
        ? input.sandboxEnabled
        : defaults.sandboxEnabled,
  };
}

import { z } from "zod";

import { createUltraChatbotAgentChatStore } from "./chat-store";

const ultraChatbotAgentCapabilitySettingsSchema = z.object({
  sandboxEnabled: z.boolean(),
});

export async function handleUltraChatbotAgentCapabilitySettingsPatchRequest(
  request: Request,
  viewer: { chatId: string; visitorId: string }
) {
  const parsedBody = ultraChatbotAgentCapabilitySettingsSchema.safeParse(
    await request.json()
  );

  if (!parsedBody.success) {
    return Response.json(
      {
        error: "A valid capability settings payload is required.",
      },
      { status: 400 }
    );
  }

  const chatStore = createUltraChatbotAgentChatStore();
  const session = await chatStore.loadChatSession(
    viewer.chatId,
    viewer.visitorId
  );

  if (!session) {
    return Response.json(
      {
        error: "Chat not found for this visitor.",
      },
      { status: 404 }
    );
  }

  const capabilities = await chatStore.setChatCapabilities({
    capabilities: {
      sandboxEnabled: parsedBody.data.sandboxEnabled,
    },
    chatId: viewer.chatId,
    visitorId: viewer.visitorId,
  });

  return Response.json(capabilities, { status: 200 });
}

import { isFileUIPart, isTextUIPart, type UIMessage } from "ai";

function getReplayableAssistantText(message: UIMessage) {
  return message.parts
    .filter(isTextUIPart)
    .map((part) => part.text)
    .join("\n")
    .trim();
}

export function projectUltraChatbotAgentHistoryForModel(messages: UIMessage[]) {
  return messages.flatMap((message) => {
    if (message.role === "assistant") {
      const text = getReplayableAssistantText(message);

      return text
        ? [
            {
              id: message.id,
              parts: [
                {
                  text,
                  type: "text" as const,
                },
              ],
              role: "assistant" as const,
            },
          ]
        : [];
    }

    if (message.role === "user") {
      const parts = message.parts.filter(
        (part) => isTextUIPart(part) || isFileUIPart(part)
      );

      return parts.length > 0
        ? [
            {
              ...message,
              parts,
            },
          ]
        : [];
    }

    if (message.role === "system") {
      const parts = message.parts.filter(isTextUIPart);

      return parts.length > 0
        ? [
            {
              ...message,
              parts,
            },
          ]
        : [];
    }

    return [];
  });
}

