export interface UltraChatbotAgentDocumentRecord {
  chatId: string | null;
  content: string | null;
  createdAt: string;
  id: string;
  kind: "code" | "image" | "sheet" | "text";
  title: string;
  visitorId: string;
}

interface UltraChatbotAgentDocumentDatabaseModule {
  database: typeof import("./database")["database"];
  ultraChatbotAgentDocuments: typeof import("./database")["ultraChatbotAgentDocuments"];
}

function toIsoString(value: Date | string) {
  return value instanceof Date ? value.toISOString() : value;
}

function normalizeDocumentRecord(record: {
  chatId: string | null;
  content: string | null;
  createdAt: Date | string;
  id: string;
  kind: "code" | "image" | "sheet" | "text";
  title: string;
  visitorId: string;
}) {
  return {
    chatId: record.chatId,
    content: record.content,
    createdAt: toIsoString(record.createdAt),
    id: record.id,
    kind: record.kind,
    title: record.title,
    visitorId: record.visitorId,
  } satisfies UltraChatbotAgentDocumentRecord;
}

async function loadUltraChatbotAgentDocumentDatabase(): Promise<UltraChatbotAgentDocumentDatabaseModule> {
  const databaseModule = await loadUltraChatbotAgentDatabase();

  return {
    database: databaseModule.database,
    ultraChatbotAgentDocuments: databaseModule.ultraChatbotAgentDocuments,
  };
}

export function createUltraChatbotAgentDocumentStore() {
  return {
    async loadLatestDocument(input: {
      chatId: string;
      documentId: string;
      visitorId: string;
    }) {
      const versions = await this.listDocumentVersions(input);

      return versions[0] ?? null;
    },
    async listDocumentVersions(input: {
      chatId: string;
      documentId: string;
      visitorId: string;
    }) {
      const { database, ultraChatbotAgentDocuments } =
        await loadUltraChatbotAgentDocumentDatabase();
      const rows = await database
        .select()
        .from(ultraChatbotAgentDocuments)
        .where(
          and(
            eq(ultraChatbotAgentDocuments.chatId, input.chatId),
            eq(ultraChatbotAgentDocuments.id, input.documentId),
            eq(ultraChatbotAgentDocuments.visitorId, input.visitorId)
          )
        )
        .orderBy(desc(ultraChatbotAgentDocuments.createdAt));

      return rows.map(normalizeDocumentRecord);
    },
    async listLatestDocumentsForChat(input: {
      chatId: string;
      limit: number;
      visitorId: string;
    }) {
      const { database, ultraChatbotAgentDocuments } =
        await loadUltraChatbotAgentDocumentDatabase();
      const rows = await database
        .select()
        .from(ultraChatbotAgentDocuments)
        .where(
          and(
            eq(ultraChatbotAgentDocuments.chatId, input.chatId),
            eq(ultraChatbotAgentDocuments.visitorId, input.visitorId)
          )
        )
        .orderBy(desc(ultraChatbotAgentDocuments.createdAt));

      const latestById = new Map<string, UltraChatbotAgentDocumentRecord>();

      for (const row of rows) {
        if (latestById.has(row.id)) {
          continue;
        }

        latestById.set(row.id, normalizeDocumentRecord(row));

        if (latestById.size >= input.limit) {
          break;
        }
      }

      return [...latestById.values()];
    },
    async saveDocument(input: {
      chatId: string;
      content: string;
      documentId: string;
      kind: "code" | "image" | "sheet" | "text";
      title: string;
      visitorId: string;
    }) {
      const { database, ultraChatbotAgentDocuments } =
        await loadUltraChatbotAgentDocumentDatabase();
      const [row] = await database
        .insert(ultraChatbotAgentDocuments)
        .values({
          chatId: input.chatId,
          content: input.content,
          createdAt: new Date(),
          id: input.documentId,
          kind: input.kind,
          title: input.title,
          visitorId: input.visitorId,
        })
        .returning();

      if (!row) {
        throw new Error("Failed to save the ultra-chatbot-agent document.");
      }

      return normalizeDocumentRecord(row);
    },
    async deleteDocumentVersionsAfterTimestamp(input: {
      chatId: string;
      documentId: string;
      timestamp: Date;
      visitorId: string;
    }) {
      const { database, ultraChatbotAgentDocuments } =
        await loadUltraChatbotAgentDocumentDatabase();
      const deletedRows = await database
        .delete(ultraChatbotAgentDocuments)
        .where(
          and(
            eq(ultraChatbotAgentDocuments.chatId, input.chatId),
            eq(ultraChatbotAgentDocuments.id, input.documentId),
            eq(ultraChatbotAgentDocuments.visitorId, input.visitorId),
            gt(ultraChatbotAgentDocuments.createdAt, input.timestamp)
          )
        )
        .returning({ id: ultraChatbotAgentDocuments.id });

      return {
        deletedCount: deletedRows.length,
      };
    },
  };
}

import type { UltraChatbotAgentDocumentRecord } from "./document-store";

const placeholderDocumentId = "00000000-0000-0000-0000-000000000000";

function normalizeTitle(value: string) {
  return value.trim().toLocaleLowerCase();
}

function normalizeDocumentId(value: string | undefined) {
  if (!value || value === placeholderDocumentId) {
    return;
  }

  return value;
}

export function getUltraChatbotAgentDocumentLookupError(input: {
  documentId?: string;
  documentTitle?: string;
  documentsCount: number;
}) {
  const documentId = normalizeDocumentId(input.documentId);

  if (input.documentTitle) {
    return `No document found with the title "${input.documentTitle}".`;
  }

  if (documentId) {
    return `No document found for ${documentId}.`;
  }

  if (input.documentsCount === 0) {
    return "There is no saved document yet. Create one before editing or updating it.";
  }

  return "More than one saved document exists. Pass a documentTitle so the tool can target the right artifact.";
}

export function findUltraChatbotAgentTargetDocument(input: {
  documentId?: string;
  documentTitle?: string;
  latestDocuments: UltraChatbotAgentDocumentRecord[];
}) {
  const documentId = normalizeDocumentId(input.documentId);
  const { documentTitle, latestDocuments } = input;

  if (documentId) {
    const matchedById =
      latestDocuments.find((document) => document.id === documentId) ?? null;

    if (matchedById) {
      return matchedById;
    }
  }

  if (documentTitle) {
    return (
      latestDocuments.find(
        (document) =>
          normalizeTitle(document.title) === normalizeTitle(documentTitle)
      ) ?? null
    );
  }

  if (latestDocuments.length === 1) {
    return latestDocuments[0];
  }

  return null;
}

import { z } from "zod";
import { createUltraChatbotAgentDocumentStore } from "./document-store";

const documentBodySchema = z.object({
  content: z.string(),
  isManualEdit: z.boolean().optional(),
  kind: z.enum(["code", "image", "sheet", "text"]),
  title: z.string().trim().min(1),
});

function getUltraChatbotAgentDocumentNotFoundError(documentId: string) {
  return `No ultra-chatbot-agent document found for ${documentId}.`;
}

export async function handleUltraChatbotAgentDocumentRequest(
  request: Request,
  viewer: { visitorId: string }
) {
  const url = new URL(request.url);
  const chatId = url.searchParams.get("chatId");
  const documentId = url.searchParams.get("id");
  const store = createUltraChatbotAgentDocumentStore();

  if (!chatId) {
    return Response.json(
      { error: 'Expected the "chatId" search parameter.' },
      { status: 400 }
    );
  }

  if (request.method === "GET") {
    if (!documentId) {
      return Response.json(
        await store.listLatestDocumentsForChat({
          chatId,
          limit: 12,
          visitorId: viewer.visitorId,
        })
      );
    }

    const documents = await store.listDocumentVersions({
      chatId,
      documentId,
      visitorId: viewer.visitorId,
    });

    if (documents.length === 0) {
      return Response.json(
        { error: getUltraChatbotAgentDocumentNotFoundError(documentId) },
        { status: 404 }
      );
    }

    return Response.json(documents);
  }

  if (request.method === "POST") {
    if (!documentId) {
      return Response.json(
        { error: 'Expected the "id" search parameter.' },
        { status: 400 }
      );
    }

    let body: z.infer<typeof documentBodySchema>;

    try {
      body = documentBodySchema.parse(await request.json());
    } catch {
      return Response.json(
        { error: "Expected a valid document payload." },
        { status: 400 }
      );
    }

    const existingDocuments = await store.listDocumentVersions({
      chatId,
      documentId,
      visitorId: viewer.visitorId,
    });
    const latestDocument = existingDocuments[0];

    if (body.isManualEdit && !latestDocument) {
      return Response.json(
        { error: getUltraChatbotAgentDocumentNotFoundError(documentId) },
        { status: 404 }
      );
    }

    const savedDocument = await store.saveDocument({
      chatId,
      content: body.content,
      documentId,
      kind: latestDocument?.kind ?? body.kind,
      title: latestDocument?.title ?? body.title,
      visitorId: viewer.visitorId,
    });

    return Response.json(savedDocument);
  }

  if (request.method === "DELETE") {
    if (!documentId) {
      return Response.json(
        { error: 'Expected the "id" search parameter.' },
        { status: 400 }
      );
    }

    const rawTimestamp = url.searchParams.get("timestamp");

    if (!rawTimestamp) {
      return Response.json(
        { error: 'Expected the "timestamp" search parameter.' },
        { status: 400 }
      );
    }

    const timestamp = new Date(rawTimestamp);

    if (Number.isNaN(timestamp.valueOf())) {
      return Response.json(
        { error: 'Expected a valid "timestamp" value.' },
        { status: 400 }
      );
    }

    const existingDocuments = await store.listDocumentVersions({
      chatId,
      documentId,
      visitorId: viewer.visitorId,
    });

    if (existingDocuments.length === 0) {
      return Response.json(
        { error: getUltraChatbotAgentDocumentNotFoundError(documentId) },
        { status: 404 }
      );
    }

    return Response.json(
      await store.deleteDocumentVersionsAfterTimestamp({
        chatId,
        documentId,
        timestamp,
        visitorId: viewer.visitorId,
      })
    );
  }

  return Response.json({ error: "Method not allowed." }, { status: 405 });
}

import { tool } from "ai";
import { z } from "zod";

import { createUltraChatbotAgentDocumentStore } from "./document-store";
import {
  findUltraChatbotAgentTargetDocument,
  getUltraChatbotAgentDocumentLookupError,
} from "./document-target";

const editDocumentInputSchema = z.object({
  documentId: z.string().uuid().optional(),
  documentTitle: z.string().trim().min(1).optional(),
  newText: z.string(),
  oldText: z.string().trim().min(1),
  replaceAll: z.boolean().optional().default(false),
});

export function createUltraChatbotAgentEditDocumentTool(input: {
  chatId: string;
  visitorId: string;
}) {
  return tool({
    description:
      "Make a targeted edit to an existing saved document by replacing exact text. Prefer this over updateDocument when the user asks for a small or local change.",
    inputSchema: editDocumentInputSchema,
    execute: async ({
      documentId,
      documentTitle,
      newText,
      oldText,
      replaceAll,
    }) => {
      const documentStore = createUltraChatbotAgentDocumentStore();
      const latestDocuments = await documentStore.listLatestDocumentsForChat({
        chatId: input.chatId,
        limit: 24,
        visitorId: input.visitorId,
      });
      const matchedDocument = findUltraChatbotAgentTargetDocument({
        documentId,
        documentTitle,
        latestDocuments,
      });

      if (!matchedDocument?.content) {
        return {
          error: getUltraChatbotAgentDocumentLookupError({
            documentId,
            documentTitle,
            documentsCount: latestDocuments.length,
          }),
        };
      }

      if (!matchedDocument.content.includes(oldText)) {
        return {
          error: `Could not find "${oldText}" in "${matchedDocument.title}".`,
        };
      }

      const nextContent = replaceAll
        ? matchedDocument.content.replaceAll(oldText, newText)
        : matchedDocument.content.replace(oldText, newText);

      const savedDocument = await documentStore.saveDocument({
        chatId: input.chatId,
        content: nextContent,
        documentId: matchedDocument.id,
        kind: matchedDocument.kind,
        title: matchedDocument.title,
        visitorId: input.visitorId,
      });

      return {
        id: savedDocument.id,
        kind: savedDocument.kind,
        title: savedDocument.title,
      };
    },
  });
}

import { tool } from "ai";
