import { tool } from "ai";
import { z } from "zod";

const weatherInputSchema = z
  .object({
    city: z.string().trim().min(1).optional(),
    latitude: z.number().optional(),
    longitude: z.number().optional(),
  })
  .refine(
    (input) =>
      Boolean(input.city) ||
      (typeof input.latitude === "number" &&
        typeof input.longitude === "number"),
    {
      message:
        "Provide either a city name or both latitude and longitude coordinates.",
    }
  );

interface UltraChatbotAgentWeatherResult {
  cityName?: string;
  current: {
    interval: number;
    temperature_2m: number;
    time: string;
  };
  current_units: {
    interval: string;
    temperature_2m: string;
    time: string;
  };
  daily: {
    sunrise: string[];
    sunset: string[];
    time: string[];
  };
  daily_units: {
    sunrise: string;
    sunset: string;
    time: string;
  };
  elevation: number;
  generationtime_ms: number;
  hourly: {
    temperature_2m: number[];
    time: string[];
  };
  hourly_units: {
    temperature_2m: string;
    time: string;
  };
  latitude: number;
  longitude: number;
  timezone: string;
  timezone_abbreviation: string;
  utc_offset_seconds: number;
}

async function geocodeCity(city: string) {
  const response = await fetch(
    `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(
      city
    )}&count=1&language=en&format=json`
  );

  if (!response.ok) {
    throw new Error(`Failed to geocode "${city}".`);
  }

  const data = (await response.json()) as {
    results?: Array<{
      latitude: number;
      longitude: number;
    }>;
  };

  const result = data.results?.[0];

  if (!result) {
    return null;
  }

  return {
    latitude: result.latitude,
    longitude: result.longitude,
  };
}

async function loadWeather(input: { latitude: number; longitude: number }) {
  const response = await fetch(
    `https://api.open-meteo.com/v1/forecast?latitude=${input.latitude}&longitude=${input.longitude}&current=temperature_2m&hourly=temperature_2m&daily=sunrise,sunset&timezone=auto`
  );

  if (!response.ok) {
    throw new Error("Failed to load the current weather.");
  }

  return (await response.json()) as UltraChatbotAgentWeatherResult;
}

export function createUltraChatbotAgentGetWeatherTool() {
  return tool({
    description:
      "Get the current weather for a city or set of coordinates. Use this when the user explicitly asks for the weather.",
    inputSchema: weatherInputSchema,
    execute: async ({ city, latitude, longitude }) => {
      let resolvedLatitude = latitude;
      let resolvedLongitude = longitude;

      if (city) {
        const coordinates = await geocodeCity(city);

        if (!coordinates) {
          return {
            error: `Could not find coordinates for "${city}".`,
          };
        }

        resolvedLatitude = coordinates.latitude;
        resolvedLongitude = coordinates.longitude;
      }

      if (
        typeof resolvedLatitude !== "number" ||
        typeof resolvedLongitude !== "number"
      ) {
        return {
          error:
            "Provide either a city name or both latitude and longitude coordinates.",
        };
      }

      const weather = await loadWeather({
        latitude: resolvedLatitude,
        longitude: resolvedLongitude,
      });

      if (city) {
        weather.cityName = city;
      }

      return weather;
    },
  });
}

import { getVercelBlobToken } from "./env";
import {
  deleteUltraChatbotAgentBlobsForChat,
  deleteUltraChatbotAgentBlobsForVisitor,
} from "./blob-storage";
import { createUltraChatbotAgentChatStore } from "./chat-store";

function clampHistoryLimit(value: string | null) {
  const parsedValue = Number.parseInt(value || "10", 10);

  if (Number.isNaN(parsedValue)) {
    return 10;
  }

  return Math.min(Math.max(parsedValue, 1), 50);
}

export async function handleUltraChatbotAgentHistoryRequest(
  request: Request,
  viewer: { visitorId: string }
) {
  const url = new URL(request.url);
  const startingAfter = url.searchParams.get("starting_after");
  const endingBefore = url.searchParams.get("ending_before");

  if (startingAfter && endingBefore) {
    return Response.json(
      {
        error: "Only one of starting_after or ending_before can be provided.",
      },
      { status: 400 }
    );
  }

  const result =
    await createUltraChatbotAgentChatStore().listChatsForVisitorPage({
      endingBefore,
      limit: clampHistoryLimit(url.searchParams.get("limit")),
      startingAfter,
      visitorId: viewer.visitorId,
    });

  return Response.json(result);
}

export async function handleUltraChatbotAgentDeleteHistoryRequest(viewer: {
  visitorId: string;
}) {
  const result =
    await createUltraChatbotAgentChatStore().deleteAllChatsForVisitor({
      visitorId: viewer.visitorId,
    });

  await deleteUltraChatbotAgentBlobsForVisitor({
    token: getVercelBlobToken(),
    visitorId: viewer.visitorId,
  });

  return Response.json(result, { status: 200 });
}

export async function handleUltraChatbotAgentDeleteChatRequest(
  chatId: string,
  viewer: {
    visitorId: string;
  }
) {
  if (chatId.trim().length === 0) {
    return Response.json(
      { error: "A valid chat id is required." },
      { status: 400 }
    );
  }

  const result = await createUltraChatbotAgentChatStore().deleteChatForVisitor({
    chatId,
    visitorId: viewer.visitorId,
  });

  if (result.deletedCount === 0) {
    return Response.json({ error: "Chat not found." }, { status: 404 });
  }

  await deleteUltraChatbotAgentBlobsForChat({
    chatId,
    token: getVercelBlobToken(),
    visitorId: viewer.visitorId,
  });

  return Response.json(result, { status: 200 });
}

import type { UIMessage } from "ai";
import { z } from "zod";

import { createUltraChatbotAgentChatStore } from "./chat-store";

const ultraChatbotAgentMessageEditSchema = z.object({
  messageId: z.string().min(1),
  retainedFileUrls: z.array(z.string().trim().min(1)).max(20).optional(),
  text: z.string().trim().min(1),
});

function buildEditedUserMessage(input: {
  message: UIMessage;
  retainedFileUrls?: string[];
  text: string;
}) {
  const retainedFileUrlSet = input.retainedFileUrls
    ? new Set(input.retainedFileUrls)
    : null;
  const preservedParts = input.message.parts.filter((part) => {
    if (part.type === "text") {
      return false;
    }

    if (part.type === "file" && retainedFileUrlSet) {
      return retainedFileUrlSet.has(part.url);
    }

    return true;
  });

  return {
    ...input.message,
    parts: [
      ...preservedParts,
      {
        text: input.text,
        type: "text" as const,
      },
    ],
  } satisfies UIMessage;
}

export async function handleUltraChatbotAgentMessageEditRequest(
  request: Request,
  viewer: { chatId: string; visitorId: string }
) {
  const parsedBody = ultraChatbotAgentMessageEditSchema.safeParse(
    await request.json()
  );

  if (!parsedBody.success) {
    return Response.json(
      {
        error: "A valid messageId and edited text are required.",
      },
      { status: 400 }
    );
  }

  const chatStore = createUltraChatbotAgentChatStore();
  const session = await chatStore.loadChatSession(
    viewer.chatId,
    viewer.visitorId
  );

  if (!session) {
    return Response.json(
      {
        error: "Chat not found for this visitor.",
      },
      { status: 404 }
    );
  }

  const targetMessage = session.messages.find(
    (message) => message.id === parsedBody.data.messageId
  );

  if (!targetMessage || targetMessage.role !== "user") {
    return Response.json(
      {
        error: "Only persisted user messages can be edited.",
      },
      { status: 400 }
    );
  }

  await chatStore.saveIncomingUserMessage({
    chatId: viewer.chatId,
    message: buildEditedUserMessage({
      message: targetMessage,
      retainedFileUrls: parsedBody.data.retainedFileUrls,
      text: parsedBody.data.text,
    }),
    selectedChatModel: session.chat.selectedChatModel,
    selectedVisibilityType: session.chat.visibility,
    visitorId: viewer.visitorId,
  });

  const result = await chatStore.deleteMessagesAfterMessage({
    chatId: viewer.chatId,
    messageId: parsedBody.data.messageId,
    visitorId: viewer.visitorId,
  });

  return Response.json(result, { status: 200 });
}

export interface UltraChatbotAgentModel {
  capabilities: {
    artifactTooling: boolean;
    attachments: {
      images: boolean;
      pdfs: boolean;
    };
    reasoning: boolean;
    tools: boolean;
    vision: boolean;
  };
