      })
    )
    .max(12)
    .optional()
    .describe(
      "Exact source records from prior web_search results. Preserve these URLs instead of inventing new ones."
    ),
  topic: z.string().trim().min(1),
});

const researchReportSourceSchema = z.object({
  title: z.string().trim().min(1),
  url: z
    .string()
    .trim()
    .min(1)
    .describe("A source URL or stable source locator from the evidence."),
});

export const researchReportSchema = z.object({
  executiveSummary: z.string().trim().min(1),
  keyFindings: z.array(z.string().trim().min(1)).min(1).max(6),
  recommendations: z.array(z.string().trim().min(1)).min(1).max(5),
  risks: z.array(z.string().trim().min(1)).max(5),
  sources: z.array(researchReportSourceSchema).max(8),
  title: z.string().trim().min(1),
  topic: z.string().trim().min(1),
});

function buildResearchReportPrompt(
  input: z.infer<typeof researchReportInputSchema>
) {
  return [
    `Topic: ${input.topic}`,
    input.audience ? `Audience: ${input.audience}` : null,
    input.evidence ? `Evidence:\n${input.evidence}` : null,
    input.sources && input.sources.length > 0
      ? `Exact sources:\n${input.sources
          .map((source) => `- ${source.title}: ${source.url}`)
          .join("\n")}`
      : null,
  ]
    .filter(Boolean)
    .join("\n\n");
}

function normalizeInputSources(
  sources: NonNullable<z.infer<typeof researchReportInputSchema>["sources"]>
) {
  const seenUrls = new Set<string>();

  return sources
    .map((source) => ({
      title: source.title.trim(),
      url: source.url.trim(),
    }))
    .filter((source) => {
      if (!(source.title && source.url) || seenUrls.has(source.url)) {
        return false;
      }

      seenUrls.add(source.url);
      return true;
    })
    .slice(0, 8);
}

export function createUltraChatbotAgentResearchReportTool(input: {
  model: Parameters<typeof generateObject>[0]["model"];
}) {
  return tool({
    description:
      "Create a structured research report object from a topic and available evidence. Use this when the user asks for a research brief, comparison report, market scan, or decision memo that should render as a structured component. If web_search was called first, pass its exact sources array in sources.",
    inputSchema: researchReportInputSchema,
    execute: async (toolInput) => {
      const suppliedSources = normalizeInputSources(toolInput.sources ?? []);
      const response = await generateObject({
        model: input.model,
        prompt: buildResearchReportPrompt(toolInput),
        schema: researchReportSchema,
        system: [
          "You create a structured research report for the Ultra Chatbot Agent.",
          "Keep findings concrete, decision-oriented, and grounded in the provided evidence.",
          "If the evidence includes URLs, preserve the most relevant sources in the sources array.",
          "If the topic requires current facts, the main agent should call web_search before this tool and pass the evidence here.",
        ].join(" "),
      });

      return {
        ...response.object,
        kind: "research-report" as const,
        sources:
          suppliedSources.length > 0
            ? suppliedSources
            : response.object.sources,
      };
    },
  });
}

import type { UIMessage } from "ai";

export type RouteBackedChatRequestTrigger =
  | "regenerate-message"
  | "submit-message";

interface PrepareRouteBackedChatReplayInput {
  incomingMessage: UIMessage;
  messageId?: string;
  persistedMessages: UIMessage[];
  trigger?: RouteBackedChatRequestTrigger;
}

interface PreparedRouteBackedChatReplay {
  messages: UIMessage[];
  trimAfterMessageId: string | null;
}

function findReplayUserIndex(input: PrepareRouteBackedChatReplayInput) {
  if (input.trigger !== "regenerate-message") {
    return -1;
  }

  if (input.messageId) {
    const targetIndex = input.persistedMessages.findIndex(
      (message) => message.id === input.messageId
    );

    if (targetIndex >= 0) {
      if (input.persistedMessages[targetIndex]?.role === "user") {
        return targetIndex;
      }

      for (let index = targetIndex - 1; index >= 0; index -= 1) {
        if (input.persistedMessages[index]?.role === "user") {
          return index;
        }
      }
    }
  }

  return input.persistedMessages.findIndex(
    (message) => message.id === input.incomingMessage.id
  );
}

export function prepareRouteBackedChatReplay(
  input: PrepareRouteBackedChatReplayInput
): PreparedRouteBackedChatReplay {
  const replayUserIndex = findReplayUserIndex(input);

  if (replayUserIndex >= 0) {
    return {
      messages: input.persistedMessages
        .slice(0, replayUserIndex)
        .concat(input.incomingMessage),
      trimAfterMessageId: input.persistedMessages[replayUserIndex]?.id ?? null,
    };
  }

  const incomingMessageIndex = input.persistedMessages.findIndex(
    (message) => message.id === input.incomingMessage.id
  );

  if (incomingMessageIndex >= 0) {
    return {
      messages: input.persistedMessages
        .slice(0, incomingMessageIndex)
        .concat(input.incomingMessage),
      trimAfterMessageId: null,
    };
  }

  return {
    messages: [...input.persistedMessages, input.incomingMessage],
    trimAfterMessageId: null,
  };
}

const appEnv = {
  // biome-ignore lint/style/noProcessEnv: Registry source installs into consumer apps without this repo's env wrapper.
  NODE_ENV: process.env.NODE_ENV,
};

export interface VisitorOwnerContext {
  isNewVisitor: boolean;
  shouldSetCookie: boolean;
  visitorId: string;
}

export interface VisitorOwner {
  appendVisitorCookie(
    response: Response,
    visitor: VisitorOwnerContext
  ): Response;
  buildVisitorCookie(visitorId: string): string;
  handleOwnedRequest(
    request: Request,
    handler: (
      request: Request,
      visitor: VisitorOwnerContext
    ) => Promise<Response>
  ): Promise<Response>;
  readVisitorIdFromCookieHeader(cookieHeader: string | null): string | null;
  resolveVisitor(request: Request): VisitorOwnerContext;
}

export function createVisitorOwner({
  cookieName,
  createVisitorId = () => crypto.randomUUID(),
  isValidVisitorId = (visitorId) => visitorId.trim().length > 0,
  maxAgeSeconds,
  secure = appEnv.NODE_ENV === "production",
}: {
  cookieName: string;
  createVisitorId?: () => string;
  isValidVisitorId?: (visitorId: string) => boolean;
  maxAgeSeconds: number;
  secure?: boolean;
}): VisitorOwner {
  function readVisitorIdFromCookieHeader(cookieHeader: string | null) {
    const visitorId = getCookieValue(cookieHeader, cookieName);

    if (typeof visitorId === "string" && isValidVisitorId(visitorId)) {
      return visitorId.trim();
    }

    return null;
  }

  function resolveVisitor(request: Request): VisitorOwnerContext {
    const visitorId = readVisitorIdFromCookieHeader(
      request.headers.get("cookie")
    );

    if (visitorId) {
      return {
        isNewVisitor: false,
        shouldSetCookie: false,
        visitorId,
      };
    }

    return {
      isNewVisitor: true,
      shouldSetCookie: true,
      visitorId: createVisitorId(),
    };
  }

  function buildVisitorCookie(visitorId: string) {
    return [
      `${cookieName}=${encodeURIComponent(visitorId)}`,
      "Path=/",
      "HttpOnly",
      "SameSite=Lax",
      secure ? "Secure" : null,
      `Max-Age=${maxAgeSeconds}`,
    ]
      .filter((part): part is string => typeof part === "string")
      .join("; ");
  }

  function appendVisitorCookie(
    response: Response,
    visitor: VisitorOwnerContext
  ) {
    if (visitor.shouldSetCookie) {
      response.headers.append(
        "set-cookie",
        buildVisitorCookie(visitor.visitorId)
      );
    }

    return response;
  }

  async function handleOwnedRequest(
    request: Request,
    handler: (
      request: Request,
      visitor: VisitorOwnerContext
    ) => Promise<Response>
  ) {
    const visitor = resolveVisitor(request);
    const response = await handler(request, visitor);
    return appendVisitorCookie(response, visitor);
  }

  return {
    appendVisitorCookie,
    buildVisitorCookie,
    handleOwnedRequest,
    readVisitorIdFromCookieHeader,
    resolveVisitor,
  };
}

function getCookieValue(cookieHeader: string | null, name: string) {
  if (!cookieHeader) {
    return null;
  }

  const cookies = cookieHeader
    .split(";")
    .map((part) => part.trim())
    .filter((part) => part.length > 0);
  const prefix = `${name}=`;
  const cookie = cookies.find((part) => part.startsWith(prefix));

  if (!cookie) {
    return null;
  }

  return decodeURIComponent(cookie.slice(prefix.length));
}

