export interface UltraChatbotAgentSuggestionRecord {
  createdAt: string;
  description: string | null;
  documentCreatedAt: string;
  documentId: string;
  id: string;
  originalText: string;
  suggestedText: string;
  visitorId: string;
}

interface UltraChatbotAgentSuggestionDatabaseModule {
  database: typeof import("./database")["database"];
  ultraChatbotAgentSuggestions: typeof import("./database")["ultraChatbotAgentSuggestions"];
}

function toIsoString(value: Date | string) {
  return value instanceof Date ? value.toISOString() : value;
}

function normalizeSuggestionRecord(record: {
  createdAt: Date | string;
  description: string | null;
  documentCreatedAt: Date | string;
  documentId: string;
  id: string;
  originalText: string;
  suggestedText: string;
  visitorId: string;
}) {
  return {
    createdAt: toIsoString(record.createdAt),
    description: record.description,
    documentCreatedAt: toIsoString(record.documentCreatedAt),
    documentId: record.documentId,
    id: record.id,
    originalText: record.originalText,
    suggestedText: record.suggestedText,
    visitorId: record.visitorId,
  } satisfies UltraChatbotAgentSuggestionRecord;
}

async function loadUltraChatbotAgentSuggestionDatabase(): Promise<UltraChatbotAgentSuggestionDatabaseModule> {
  const databaseModule = await loadUltraChatbotAgentDatabase();

  return {
    database: databaseModule.database,
    ultraChatbotAgentSuggestions: databaseModule.ultraChatbotAgentSuggestions,
  };
}

export function createUltraChatbotAgentSuggestionStore() {
  return {
    async listSuggestionsForDocumentVersion(input: {
      documentCreatedAt: string;
      documentId: string;
      visitorId: string;
    }) {
      const { database, ultraChatbotAgentSuggestions } =
        await loadUltraChatbotAgentSuggestionDatabase();
      const rows = await database
        .select()
        .from(ultraChatbotAgentSuggestions)
        .where(
          and(
            eq(ultraChatbotAgentSuggestions.documentId, input.documentId),
            eq(
              ultraChatbotAgentSuggestions.documentCreatedAt,
              new Date(input.documentCreatedAt)
            ),
            eq(ultraChatbotAgentSuggestions.visitorId, input.visitorId)
          )
        )
        .orderBy(asc(ultraChatbotAgentSuggestions.createdAt));

      return rows.map(normalizeSuggestionRecord);
    },
    async replaceSuggestionsForDocumentVersion(input: {
      documentCreatedAt: string;
      documentId: string;
      suggestions: Array<{
        description: string | null;
        originalText: string;
        suggestedText: string;
      }>;
      visitorId: string;
    }) {
      const { database, ultraChatbotAgentSuggestions } =
        await loadUltraChatbotAgentSuggestionDatabase();

      await database
        .delete(ultraChatbotAgentSuggestions)
        .where(
          and(
            eq(ultraChatbotAgentSuggestions.documentId, input.documentId),
            eq(
              ultraChatbotAgentSuggestions.documentCreatedAt,
              new Date(input.documentCreatedAt)
            ),
            eq(ultraChatbotAgentSuggestions.visitorId, input.visitorId)
          )
        );

      if (input.suggestions.length === 0) {
        return [] satisfies UltraChatbotAgentSuggestionRecord[];
      }

      const createdAt = new Date();
      const rows = await database
        .insert(ultraChatbotAgentSuggestions)
        .values(
          input.suggestions.map((suggestion) => ({
            createdAt,
            description: suggestion.description,
            documentCreatedAt: new Date(input.documentCreatedAt),
            documentId: input.documentId,
            id: crypto.randomUUID(),
            originalText: suggestion.originalText,
            suggestedText: suggestion.suggestedText,
            visitorId: input.visitorId,
          }))
        )
        .returning();

      return rows.map(normalizeSuggestionRecord);
    },
  };
}

import { createUltraChatbotAgentDocumentStore } from "./document-store";
import { createUltraChatbotAgentSuggestionStore } from "./suggestion-store";

function getUltraChatbotAgentSuggestionNotFoundError(documentId: string) {
  return `No ultra-chatbot-agent document found for ${documentId}.`;
}

export async function handleUltraChatbotAgentSuggestionsRequest(
  request: Request,
  viewer: { visitorId: string }
) {
  if (request.method !== "GET") {
    return Response.json({ error: "Method not allowed." }, { status: 405 });
  }

  const url = new URL(request.url);
  const chatId = url.searchParams.get("chatId");
  const documentId = url.searchParams.get("id");

  if (!chatId) {
    return Response.json(
      { error: 'Expected the "chatId" search parameter.' },
      { status: 400 }
    );
  }

  if (!documentId) {
    return Response.json(
      { error: 'Expected the "id" search parameter.' },
      { status: 400 }
    );
  }

  const latestDocument =
    await createUltraChatbotAgentDocumentStore().loadLatestDocument({
      chatId,
      documentId,
      visitorId: viewer.visitorId,
    });

  if (!latestDocument) {
    return Response.json(
      { error: getUltraChatbotAgentSuggestionNotFoundError(documentId) },
      { status: 404 }
    );
  }

  return Response.json(
    await createUltraChatbotAgentSuggestionStore().listSuggestionsForDocumentVersion(
      {
        documentCreatedAt: latestDocument.createdAt,
        documentId,
        visitorId: viewer.visitorId,
      }
    )
  );
}

import { generateText, tool } from "ai";
import { z } from "zod";

import { createUltraChatbotAgentDocumentStore } from "./document-store";
import {
  findUltraChatbotAgentTargetDocument,
  getUltraChatbotAgentDocumentLookupError,
} from "./document-target";
import { getUltraChatbotAgentDocumentRewriteSystemPrompt } from "./prompts";

const updateDocumentInputSchema = z.object({
  description: z.string().trim().min(1),
  documentId: z.string().uuid().optional(),
  documentTitle: z.string().trim().min(1).optional(),
});

export function createUltraChatbotAgentUpdateDocumentTool(input: {
  chatId: string;
  model: Parameters<typeof generateText>[0]["model"];
  visitorId: string;
}) {
  return tool({
    description:
      "Rewrite an existing saved document more broadly from a change description. Use this when the user asks for a larger refresh or major rewrite, and prefer editDocument for small exact replacements.",
    inputSchema: updateDocumentInputSchema,
    execute: async ({ description, documentId, documentTitle }) => {
      const documentStore = createUltraChatbotAgentDocumentStore();
      const latestDocuments = await documentStore.listLatestDocumentsForChat({
        chatId: input.chatId,
        limit: 24,
        visitorId: input.visitorId,
      });
      const matchedDocument = findUltraChatbotAgentTargetDocument({
        documentId,
        documentTitle,
        latestDocuments,
      });

      if (!matchedDocument?.content) {
        return {
          error: getUltraChatbotAgentDocumentLookupError({
            documentId,
            documentTitle,
            documentsCount: latestDocuments.length,
          }),
        };
      }

      const response = await generateText({
        model: input.model,
        prompt: [
          `Document title: ${matchedDocument.title}`,
          `Document kind: ${matchedDocument.kind}`,
          `Requested rewrite: ${description}`,
          "Current content:",
          matchedDocument.content,
        ].join("\n\n"),
        system: getUltraChatbotAgentDocumentRewriteSystemPrompt(),
      });

      const nextContent = response.text.trim();

      if (!nextContent) {
        throw new Error("The model returned an empty document rewrite.");
      }

      const savedDocument = await documentStore.saveDocument({
        chatId: input.chatId,
        content: nextContent,
        documentId: matchedDocument.id,
        kind: matchedDocument.kind,
        title: matchedDocument.title,
        visitorId: input.visitorId,
      });

      return {
        id: savedDocument.id,
        kind: savedDocument.kind,
        title: savedDocument.title,
      };
    },
  });
}

import { put } from "@vercel/blob";
import { z } from "zod";

import { getUltraChatbotAgentAppEnv } from "./env";

const appEnv = getUltraChatbotAgentAppEnv();
import { getVercelBlobToken } from "./env";

import {
  isUltraChatbotAgentAcceptedUploadMediaType,
  ultraChatbotAgentAcceptedUploadMediaTypes,
  ultraChatbotAgentMaxUploadBytes,
} from "../attachment-config";
import {
  buildUltraChatbotAgentDailyUploadPrefix,
  buildUltraChatbotAgentUploadPath,
  formatUltraChatbotAgentUploadDateBucket,
  readUltraChatbotAgentBlobUsageForPrefix,
  validateUltraChatbotAgentBlobPathSegment,
} from "./blob-storage";

const uploadFileSchema = z.object({
  chatId: z.string().trim().min(1, {
    message: "A chat id is required.",
  }),
  file: z
    .instanceof(Blob)
    .refine((file) => file.size <= ultraChatbotAgentMaxUploadBytes, {
      message: "File size should be less than 5MB.",
    })
    .refine((file) => isUltraChatbotAgentAcceptedUploadMediaType(file.type), {
      message: "File type should be PDF, JPEG, or PNG.",
    }),
});

const ultraChatbotAgentDailyUploadFileLimit = 20;
const ultraChatbotAgentDailyUploadBytesLimit = 50 * 1024 * 1024;

export interface UltraChatbotAgentUploadEnv {
  BLOB_READ_WRITE_TOKEN?: string;
}

export interface UltraChatbotAgentUploadViewer {
  visitorId: string;
}

export interface UltraChatbotAgentUploadOptions {
  now?: Date;
}

export function getUltraChatbotAgentAcceptedUploadMediaTypes() {
  return [...ultraChatbotAgentAcceptedUploadMediaTypes];
}

function sanitizeFilename(filename: string) {
  const trimmed = filename.trim();

  if (trimmed.length === 0) {
    return "attachment";
  }

  return trimmed.replace(/[^a-zA-Z0-9._-]/g, "_");
}

export async function handleUltraChatbotAgentFileUploadRequest(
  request: Request,
  viewer: UltraChatbotAgentUploadViewer,
  env: UltraChatbotAgentUploadEnv = appEnv,
  options: UltraChatbotAgentUploadOptions = {}
) {
  if (request.body === null) {
    return Response.json({ error: "Request body is empty." }, { status: 400 });
  }

  let formData: FormData;

  try {
    formData = await request.formData();
  } catch {
    return Response.json(
      { error: "Failed to process the upload request." },
      { status: 500 }
    );
  }

  const maybeFile = formData.get("file");
  const maybeChatId = formData.get("chatId");

  if (!(maybeFile instanceof Blob)) {
    return Response.json({ error: "No file uploaded." }, { status: 400 });
  }

  if (typeof maybeChatId !== "string") {
    return Response.json({ error: "A chat id is required." }, { status: 400 });
  }

  const validatedUpload = uploadFileSchema.safeParse({
    chatId: maybeChatId,
    file: maybeFile,
  });

  if (!validatedUpload.success) {
    return Response.json(
      {
        error: validatedUpload.error.issues
          .map((issue) => issue.message)
          .join(" "),
      },
      { status: 400 }
    );
  }

  let token: string;

  try {
    token = getVercelBlobToken(env);
  } catch (error) {
    return Response.json(
      {
        error:
          error instanceof Error
            ? error.message
            : "Blob storage is not configured.",
      },
      { status: 500 }
    );
  }

  const file = validatedUpload.data.file;
  const dateBucket = formatUltraChatbotAgentUploadDateBucket(
    options.now ?? new Date()
  );
  let visitorId: string;
  let chatId: string;

  try {
    visitorId = validateUltraChatbotAgentBlobPathSegment(
      viewer.visitorId,
      "Visitor id"
    );
    chatId = validateUltraChatbotAgentBlobPathSegment(
      validatedUpload.data.chatId,
      "Chat id"
    );
  } catch (error) {
    return Response.json(
      {
        error:
          error instanceof Error
            ? error.message
            : "Invalid upload ownership path.",
      },
      { status: 400 }
    );
  }

  const dailyPrefix = buildUltraChatbotAgentDailyUploadPrefix({
    dateBucket,
    visitorId,
  });

  try {
    const dailyUsage = await readUltraChatbotAgentBlobUsageForPrefix({
      prefix: dailyPrefix,
      token,
    });

    if (
      dailyUsage.fileCount >= ultraChatbotAgentDailyUploadFileLimit ||
      dailyUsage.totalBytes + file.size > ultraChatbotAgentDailyUploadBytesLimit
    ) {
      return Response.json(
        { error: "Daily upload quota exceeded." },
        { status: 429 }
      );
    }
  } catch {
    return Response.json(
      { error: "Upload quota check failed." },
      { status: 500 }
    );
  }

  const filename =
    maybeFile instanceof File && maybeFile.name ? maybeFile.name : "attachment";
  const pathname = buildUltraChatbotAgentUploadPath({
    chatId,
    dateBucket,
    filename: sanitizeFilename(filename),
    uploadId: crypto.randomUUID(),
    visitorId,
  });

  try {
    const uploadedBlob = await put(pathname, file, {
      access: "public",
      token,
    });

    return Response.json({
      contentType: uploadedBlob.contentType,
      pathname: uploadedBlob.pathname,
      size: file.size,
      url: uploadedBlob.url,
    });
  } catch {
    return Response.json({ error: "Upload failed." }, { status: 500 });
  }
}

