import { z } from "zod";

import { createUltraChatbotAgentChatStore } from "./chat-store";

const ultraChatbotAgentVisibilitySchema = z.object({
  visibility: z.enum(["private", "public"]),
});

export async function handleUltraChatbotAgentVisibilityPatchRequest(
  request: Request,
  viewer: { chatId: string; visitorId: string }
) {
  const parsedBody = ultraChatbotAgentVisibilitySchema.safeParse(
    await request.json()
  );

  if (!parsedBody.success) {
    return Response.json(
      {
        error: "A valid visibility value is required.",
      },
      { status: 400 }
    );
  }

  const chatStore = createUltraChatbotAgentChatStore();
  const session = await chatStore.loadChatSession(
    viewer.chatId,
    viewer.visitorId
  );

  if (!session) {
    return Response.json(
      {
        error: "Chat not found for this visitor.",
      },
      { status: 404 }
    );
  }

  const updatedChat = await chatStore.setChatVisibility({
    chatId: viewer.chatId,
    visibility: parsedBody.data.visibility,
    visitorId: viewer.visitorId,
  });

  return Response.json(updatedChat, { status: 200 });
}

import { z } from "zod";

import { createUltraChatbotAgentChatStore } from "./chat-store";

const ultraChatbotAgentVoteSchema = z.object({
  chatId: z.string().uuid(),
  messageId: z.string().min(1),
  type: z.enum(["up", "down", "clear"]),
});

function notFoundResponse() {
  return Response.json(
    {
      error: "Chat not found for this visitor.",
    },
    { status: 404 }
  );
}

export async function handleUltraChatbotAgentVoteListRequest(
  request: Request,
  viewer: { visitorId: string }
) {
  const chatId = new URL(request.url).searchParams.get("chatId");

  if (!chatId) {
    return Response.json(
      {
        error: "Parameter chatId is required.",
      },
      { status: 400 }
    );
  }

  const chatStore = createUltraChatbotAgentChatStore();
  const session = await chatStore.loadChatSession(chatId, viewer.visitorId);

  if (!session) {
    return notFoundResponse();
  }

  const votes = await chatStore.listVotesForChat({
    chatId,
    visitorId: viewer.visitorId,
  });

  return Response.json(votes, { status: 200 });
}

export async function handleUltraChatbotAgentVotePatchRequest(
  request: Request,
  viewer: { visitorId: string }
) {
  const parsedBody = ultraChatbotAgentVoteSchema.safeParse(
    await request.json()
  );

  if (!parsedBody.success) {
    return Response.json(
      {
        error: "Parameters chatId, messageId, and type are required.",
      },
      { status: 400 }
    );
  }

  const chatStore = createUltraChatbotAgentChatStore();
  const session = await chatStore.loadChatSession(
    parsedBody.data.chatId,
    viewer.visitorId
  );

  if (!session) {
    return notFoundResponse();
  }

  if (parsedBody.data.type === "clear") {
    await chatStore.deleteVote({
      chatId: parsedBody.data.chatId,
      messageId: parsedBody.data.messageId,
      visitorId: viewer.visitorId,
    });
  } else {
    await chatStore.saveVote({
      chatId: parsedBody.data.chatId,
      isUpvoted: parsedBody.data.type === "up",
      messageId: parsedBody.data.messageId,
      visitorId: viewer.visitorId,
    });
  }

  return new Response("Message voted", { status: 200 });
}

import { generateText, stepCountIs, tool } from "ai";
import { z } from "zod";

const webSearchInputSchema = z.object({
  query: z.string().trim().min(1),
});

interface UltraChatbotAgentWebSearchToolSource {
  title: string;
  url: string;
}

interface UltraChatbotAgentGeneratedSource {
  title?: string | null;
  type?: string | null;
  url?: string | null;
}

const markdownLinkPattern = /\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g;
const explicitUrlPattern = /\bhttps?:\/\/[^\s)]+/g;

function normalizeCitationUrl(value: string) {
  return value.trim().replace(/[),.;]+$/g, "");
}

function normalizeSearchSource(
  source: UltraChatbotAgentGeneratedSource
): UltraChatbotAgentWebSearchToolSource | null {
  if (source.type !== "source") {
    return null;
  }

  const url = typeof source.url === "string" ? source.url.trim() : "";

  if (!url) {
    return null;
  }

  return {
    title:
      typeof source.title === "string" && source.title.trim().length > 0
        ? source.title.trim()
        : url,
    url,
  };
}

function collectSourcesFromSummary(summary: string) {
  const sources = new Map<string, UltraChatbotAgentWebSearchToolSource>();

  for (const match of summary.matchAll(markdownLinkPattern)) {
    const [, label, rawUrl] = match;

    if (typeof rawUrl !== "string") {
      continue;
    }

    const url = normalizeCitationUrl(rawUrl);
    const title = typeof label === "string" ? label.trim() : "";

    if (!url) {
      continue;
    }

    sources.set(url, {
      title: title || url,
      url,
    });
  }

  for (const match of summary.matchAll(explicitUrlPattern)) {
    const url = normalizeCitationUrl(match[0]);

    if (!url || sources.has(url)) {
      continue;
    }

    sources.set(url, {
      title: url.replace(/^https?:\/\//, ""),
      url,
    });
  }

  return [...sources.values()];
}

export function createUltraChatbotAgentWebSearchTool(input: {
  model: Parameters<typeof generateText>[0]["model"];
  webSearchTool: NonNullable<
    Parameters<typeof generateText>[0]["tools"]
  >[string];
}) {
  return tool({
    description:
      "Search the public web for current information and return grounded notes plus concrete sources.",
    inputSchema: webSearchInputSchema,
    execute: async ({ query }) => {
      const result = await generateText({
        model: input.model,
        prompt: query,
        stopWhen: stepCountIs(5),
        system: [
          "You are the Ultra agent's research helper.",
          "Use web_search when the query needs current or external facts.",
          "Return a short synthesis grounded in the search results.",
          "Cite at least two concrete sources when enough evidence is available.",
        ].join(" "),
        tools: {
          web_search: input.webSearchTool,
        },
      });

      const summary = result.text.trim();
      const explicitSources = result.sources
        .map(normalizeSearchSource)
        .filter(
          (source): source is UltraChatbotAgentWebSearchToolSource =>
            source !== null
        );

      return {
        query,
        summary,
        sources:
          explicitSources.length > 0
            ? explicitSources
            : collectSourcesFromSummary(summary),
      };
    },
  });
}

import {
  createAgentUIStreamResponse,
  stepCountIs,
  ToolLoopAgent,
  type UIMessage,
} from "ai";
import { z } from "zod";
import { createSkillsAgentGateway, getSkillsAgentEnv } from "./env";
import {
  resolveSkillsAgentChatModel,
  SKILLS_AGENT_PROVIDER_OPTIONS,
} from "./model";
import type { SkillMetadata } from "./skill-catalog";
import { createSkillsAgentWorkspace } from "./workspace";

type DemoEnv = Record<string, string | undefined>;

const skillOptionSchema = z.object({
  description: z.string(),
  name: z.string(),
  path: z.string(),
});

const skillsAgentCallOptionsSchema = z.object({
  skills: z.array(skillOptionSchema).min(1),
});

type SkillsAgentCallOptions = z.infer<typeof skillsAgentCallOptionsSchema>;

export const skillsAgentInstructions = [
  "You are the skills-agent demo for a product and engineering team.",
  "Treat the visible skill catalog as lightweight metadata. Load the full SKILL.md only when you decide a skill is needed.",
  "Choose a skill based on the visible catalog descriptions when the user's request matches one of them.",
  "Use readFile, writeFile, and bash inside the active sandbox workspace when the skill instructions require repository context or generated artifacts.",
  "Follow the loaded skill's filesystem conventions. grill-with-docs owns repository paths like CONTEXT.md and docs/adr/, while artifacts/ is for standalone drafts when a skill does not specify a canonical location.",
  "Repository files such as CONTEXT.md or docs/adr/ may not exist yet. Use bash checks like test -f or ls before reading optional files, and create them lazily when the loaded skill calls for that.",
  "Keep the final answer concise and report any artifact paths that were created or updated.",
].join(" ");

export async function streamSkillsAgent(
  messages: UIMessage[],
  {
    env = getSkillsAgentEnv(),
    sessionId,
    skills,
  }: {
    env?: DemoEnv;
    sessionId: string;
    skills: SkillMetadata[];
  }
) {
  const gateway = createSkillsAgentGateway(env);
  const chatModel = resolveSkillsAgentChatModel(env);
  const workspace = await createSkillsAgentWorkspace({
    env,
    sessionId,
    skills,
  });

  const agent = new ToolLoopAgent<SkillsAgentCallOptions>({
    instructions: skillsAgentInstructions,
    model: gateway(chatModel),
    prepareCall: (call) => ({
      ...call,
      instructions: [
        skillsAgentInstructions,
        `Visible skill catalog:\n${workspace.visibleSkillCatalogText}`,
        `Sandbox project root: ${workspace.projectRoot}`,
        `Default artifacts root: ${workspace.artifactsRoot}`,
      ].join("\n\n"),
    }),
    providerOptions: SKILLS_AGENT_PROVIDER_OPTIONS,
    callOptionsSchema: skillsAgentCallOptionsSchema,
    stopWhen: stepCountIs(20),
    tools: workspace.toolset.tools,
  });

  return await createAgentUIStreamResponse({
    agent,
    options: {
      skills: workspace.visibleSkillCatalog,
    },
    sendReasoning: true,
    uiMessages: messages,
  });
}

